code = """import json

reviews = var_call_nC5DfcA3KTJeIcgIIBRjeC5T
books_path = var_call_TQEJqJJ7UgfazlLOSLDrs1Yl

# Build rating map from reviews
rating_map = {}
for r in reviews:
    pid = r.get('purchase_id')
    if not pid:
        continue
    digits = ''.join([c for c in str(pid) if c.isdigit()])
    if not digits:
        continue
    bid = 'bookid_' + digits
    try:
        avg = float(r.get('avg_rating') or 0.0)
    except Exception:
        avg = 0.0
    try:
        rc = int(r.get('review_count') or 0)
    except Exception:
        rc = 0
    rating_map[bid] = {'avg_rating': avg, 'review_count': rc}

selected = {bid for bid, v in rating_map.items() if v['avg_rating'] >= 4.5}

# Load books
with open(books_path, 'r', encoding='utf-8') as f:
    books = json.load(f)

matches = []
for b in books:
    bid = b.get('book_id')
    if not bid or bid not in selected:
        continue
    cats = b.get('categories')
    if cats is None:
        continue
    if 'children' in str(cats).lower():
        info = rating_map.get(bid, {})
        matches.append({'book_id': bid, 'title': b.get('title'), 'avg_rating': info.get('avg_rating'), 'review_count': info.get('review_count'), 'categories': cats})

# sort
matches.sort(key=lambda x: (x.get('avg_rating') or 0, x.get('review_count') or 0), reverse=True)

out = {'matches': matches}
print("__RESULT__:")
print(json.dumps(out))"""

